import { Model } from '@topwrite/common';

interface SearchResult {
    title: string
    path: string
    body?: string
}

type Handler = (keyword: string) => Promise<SearchResult[]> | SearchResult[]

interface SearchState {
    handler?: Handler
    results?: SearchResult[]
    keyword?: string
    fetching: boolean
}

class Search extends Model<SearchState> {

    initialState = {
        fetching: false
    };

    async *fetch(keyword: string) {
        keyword = keyword.trim();

        if (keyword) {

            yield this.setState(state => {
                state.keyword = keyword;
            });

            let { handler } = yield *this.getState('search');
            if (!handler) {
                const { summary } = yield *this.getState('book');

                handler = () => {
                    const results: SearchResult[] = [];
                    summary.getArticle((article) => {
                        if (article.title.includes(keyword)) {
                            results.push({
                                title: article.title,
                                path: article.getPath()
                            });
                        }
                        return false;
                    });
                    return results;
                };
            }

            const results = await handler(keyword);

            yield this.setState(state => {
                state.results = results;
            });

        }

    }

    *setHandler(handler?: Handler) {
        yield this.setState((state) => {
            state.handler = handler;
        });
    }

}

export const search = new Search();
